import React from 'react';
import './Analytics.css';

const Analytics = () => {
  const categories = [
    { name: 'Manga', value: 45, color: '#ff6b6b' },
    { name: 'Manhwa', value: 30, color: '#4ecdc4' },
    { name: 'Video', value: 25, color: '#45b7d1' }
  ];

  return (
    <div className="analytics">
      <h2>Analytics</h2>
      <div className="analytics-grid">
        <div className="analytics-card">
          <h3>Popularity by category</h3>
          <div className="category-stats">
            {categories.map((category) => (
              <div key={category.name} className="category-item">
                <div className="category-info">
                  <span className="category-name">{category.name}</span>
                  <span className="category-value">{category.value}%</span>
                </div>
                <div className="category-bar">
                  <div className="bar-fill" style={{ width: `${category.value}%`, backgroundColor: category.color }}></div>
                </div>
              </div>
            ))}
          </div>
        </div>

        <div className="analytics-card">
          <h3>Top titles</h3>
          <div className="top-content-list">
            {[
              { title: 'Berserk', views: '1.2M' },
              { title: 'Solo Leveling', views: '980K' },
              { title: 'One Piece', views: '850K' }
            ].map((item, index) => (
              <div key={item.title} className="top-content-item">
                <div className="content-rank"><span className={`rank-number ${index < 3 ? 'top-three' : ''}`}>{index + 1}</span></div>
                <div className="content-info">
                  <span className="content-title">{item.title}</span>
                  <span className="content-views">{item.views} views</span>
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

export default Analytics;
